VALUES
  ('locality-6f0ba476-moex-00125', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於合夥之敘述，何者正確？', '["若合夥契約未特別訂定，合夥人之出資，得以勞務或信用代之", "若合夥契約未特別訂定，各合夥人之出資及其他合夥財產，為合夥人全體之分別共有", "合夥人除契約另有訂定外，負有於約定出資之外增加出資之義務", "合夥人除契約另有訂定外，因損失而致資本減少者，合夥人有補充之義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00126', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲有A地，與乙訂立A地買賣契約。嗣後，因丙出價更高，甲又與丙訂立A地買賣契約。下列 敘述，何者正確？', '["甲與丙及甲與乙之A地買賣契約皆為有效", "甲得解除與乙之買賣契約", "乙得主張甲與丙之買賣無效", "甲與丙訂立契約之行為，構成無權處分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00127', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於連帶債務之敘述，何者正確？', '["對連帶債務人中之一人已為清償或為其他消滅債務之行為，他債務人亦同免其責任", "基於債務人之個人關係所作之確定判決，對他連帶債務人均生效力", "非基於債務人之個人關係，且為他債務人之利益所作之確定判決，對其他連帶債務人不發生效力", "債權人對連帶債務人中之一人有受領遲延時，他債務人之注意義務，不得僅就故意或重大過失 負責"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00128', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列何種物權，權利人原則上不得對標的物為使用、收益？', '["留置權", "典權", "不動產役權", "農育權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00129', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '關於動產所有權之善意取得，依法受讓人在受讓該動產時須為善意。下列關於善意時點之敘述， 何者錯誤？', '["在現實交付方式，係指讓與人將該動產交付於受讓人之時", "在簡易交付方式，係指讓與人與受讓人達成該動產讓與合意之時", "在指示交付方式，係指受讓人取得讓與人所讓與之返還請求權之時", "在占有改定方式，係指讓與人與受讓人訂立契約使受讓人取得間接占有之時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00130', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於占有狀態及占有人之敘述，何者錯誤？', '["出租人對出租物之占有為間接占有", "依僱用人指示對物為占有之受僱人為該物之直接占有人", "竊取他人印章存摺後至存款銀行請求付款者，為該債權之準占有人", "占有輔助人對於侵奪其占有之行為，得以己力防禦之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00131', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲對乙負有新臺幣（下同）1,200萬元之債務，由丙擔任連帶保證人，丁則提供其名下市值2,400 萬元之A地設定普通抵押權於乙。嗣後，甲逾期未能清償，乙遂先聲請拍賣丁之A地而受償1,200 萬元，下列敘述，何者錯誤？', '["丁對丙得求償600萬元", "丙、丁之應分擔比例為1：1", "丙、丁之應分擔比例為1：2", "丁於其清償之限度內，承受乙對甲之債權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00132', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列設定何者毋須以書面為之？', '["留置權", "最高限額質權", "普通抵押權", "債權質權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00133', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於不動產登記之敘述，何者錯誤？', '["不動產物權，依法律行為而取得、設定、變更或喪失者，非經登記，不生效力。該登記為設權 登記", "非依法律行為而於登記前已取得不動產物權者，應經登記，始得處分其物權。該登記為宣示登記", "不動產物權經登記者，推定登記權利人適法有此權利，故登記名義人不得援以對抗前手之真正 權利人，僅得向其他人主張", "不動產物權一經登記，有絕對之效力，得對任何人主張其權利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00134', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲夫乙妻結婚後，生有一子丙，丙現年10歲。依民法關於離婚之規定，下列敘述，何者錯誤？', '["設甲乙兩願離婚，丙離婚後之親權行使，由甲乙共同協議，由一方或雙方共同任之", "甲如對丙為虐待，致不堪為共同生活者，乙得向法院請求離婚", "設甲乙經法院判決離婚，甲為無過失之一方，甲如因判決離婚而陷於生活困難者，乙縱無過失， 亦應給與甲相當之贍養費", "設甲向法院請求離婚，其離婚如經法院調解成立者，甲乙應至戶政機關辦理登記後，甲乙之婚 姻關係始消滅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "6949d71b8c08", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
